import React, { useEffect, useState } from 'react';
import axios from 'axios';

const STATUS_LABELS = {
  'Novo': 'Novo',
  'Retorno': 'Retorno',
  'Solicitado': 'Solicitado',
};
const STATUS_COLORS = {
  'Novo': "bg-[#2FA74E] text-white",
  'Retorno': "bg-[#278FFF] text-white",
  'Solicitado': "bg-[#DA3648] text-white",
};

export default function ListaAgendamentos({ onEditar, reloadKey }) {
  const [agendamentos, setAgendamentos] = useState([]);
  const [carregando, setCarregando] = useState(true);

  // Filtros e busca
  const [busca, setBusca] = useState('');
  const [filtroData, setFiltroData] = useState('');
  const [filtroHora, setFiltroHora] = useState('');

  useEffect(() => {
    setCarregando(true);
    axios.get('/api/agendamentos')
      .then((res) => {
        setAgendamentos(res.data);
        setCarregando(false);
      })
      .catch((err) => {
        console.error('Erro ao buscar agendamentos:', err);
        setCarregando(false);
      });
  }, [reloadKey]);

  // Função para filtrar com base na busca e filtros de data/hora
  const filtrarAgendamentos = (lista) => {
    return lista.filter(ag => {
      const textoBusca = busca.toLowerCase();
      const campos = [
        ag.operadorNome,
        ag.auxiliarNome,
        ag.disciplinaNome,
        ag.pacienteNome,
        ag.telefone,
        ag.status
      ].map(x => x ? x.toLowerCase() : '');
      const matchTexto = campos.some(campo => campo.includes(textoBusca));
      const matchData = filtroData ? (ag.data && ag.data.startsWith(filtroData)) : true;
      const matchHora = filtroHora ? (ag.hora && ag.hora.startsWith(filtroHora)) : true;
      return matchTexto && matchData && matchHora;
    });
  };

  const agendamentosFiltrados = filtrarAgendamentos(agendamentos).slice(0, 100);

  // Pega o nome da disciplina e data do primeiro agendamento filtrado para exibir no topo
  const disciplinaNome = agendamentosFiltrados[0]?.disciplinaNome || '';
  const dataAtual = agendamentosFiltrados[0]?.data ? agendamentosFiltrados[0].data.slice(0, 10).split('-').reverse().join('/') : '';
  const semestre = ""; // adapte conforme seu projeto

  // Impressão direta: gera HTML, abre nova janela e imprime
  const handleImprimir = () => {
    const conteudo = `
      <div style="background:#fff;padding:32px;">
        <h2 style="font-size:24px;font-weight:bold;margin-bottom:8px;">Lista de Agendamentos</h2>
        <div style="font-size:18px;">
          <div><b>Disciplina:</b> ${disciplinaNome}</div>
          <div><b>Semestre:</b> ${semestre}</div>
          <div><b>Data:</b> ${dataAtual}</div>
        </div>
        <table border="1" cellspacing="0" cellpadding="8" style="margin-top:24px;width:100%;border-collapse:collapse;font-size:16px;">
          <thead>
            <tr>
              <th style="padding:8px 12px;">N°</th>
              <th style="padding:8px 12px;">Operador</th>
              <th style="padding:8px 12px;">Auxiliar</th>
              <th style="padding:8px 12px;">Paciente</th>
              <th style="padding:8px 12px;">Telefone</th>
              <th style="padding:8px 12px;">Status</th>
            </tr>
          </thead>
          <tbody>
            ${agendamentosFiltrados.map((ag, idx) => `
              <tr>
                <td style="padding:8px 12px;">${idx + 1}</td>
                <td style="padding:8px 12px;">${ag.operadorNome || ''}</td>
                <td style="padding:8px 12px;">${ag.auxiliarNome || ''}</td>
                <td style="padding:8px 12px;">${ag.pacienteNome || ''}</td>
                <td style="padding:8px 12px;">${ag.telefone || ''}</td>
                <td style="padding:8px 12px;">${STATUS_LABELS[ag.status] || ag.status}</td>
              </tr>
            `).join('')}
          </tbody>
        </table>
        <style>
          @media print {
            body { background: #fff !important; }
          }
        </style>
      </div>
    `;
    const win = window.open('', '', 'width=900,height=650');
    win.document.write('<html><head><title>Imprimir Lista</title></head><body>');
    win.document.write(conteudo);
    win.document.write('</body></html>');
    win.document.close();
    setTimeout(() => {
      win.print();
      win.close();
    }, 350);
  };

  const handleDeletar = (id) => {
    if (window.confirm('Tem certeza que deseja deletar este agendamento?')) {
      axios.delete(`/api/agendamentos/${id}`)
        .then(() => {
          setAgendamentos(agendamentos.filter(a => a.id !== id));
        })
        .catch(() => alert('Erro ao deletar agendamento'));
    }
  };

  if (carregando) return <p>Carregando agendamentos...</p>;
  if (agendamentos.length === 0) return <p>Nenhum agendamento cadastrado.</p>;

  return (
    <div className="bg-white rounded-2xl shadow p-0 overflow-x-auto mt-2 max-h-[70vh] overflow-y-auto">
      {/* Campo de busca e filtros */}
      <div className="flex flex-col md:flex-row md:items-end gap-3 p-4 pt-0 pb-4 rounded-2xl">
        <div className="flex-1">
          <label className="block text-xs font-medium mb-2">Pesquisar</label>
          <input
            type="text"
            className="border rounded px-4 py-2 w-full rounded-2xl"
            placeholder="Operador, Auxiliar, Disciplina, Paciente, Telefone ou Status"
            value={busca}
            onChange={e => setBusca(e.target.value)}
          />
        </div>
        <div>
          <label className="block text-sm font-medium mb-1">Data</label>
          <input
            type="date"
            className="border rounded px-3 py-2 rounded-2xl"
            value={filtroData}
            onChange={e => setFiltroData(e.target.value)}
          />
        </div>
        <div>
          <label className="block text-sm font-medium mb-1">Hora</label>
          <input
            type="time"
            className="border rounded px-3 py-2 rounded-2xl"
            value={filtroHora}
            onChange={e => setFiltroHora(e.target.value)}
          />
        </div>
        <div>
          <button
            className="block bg-[#3172C0] text-white rounded-full font-medium px-4 py-2 mb-1 hover:bg-[#083A76] transition"
            onClick={handleImprimir}
            type="button"
          >
            Imprimir Lista
          </button>
        </div>
      </div>

      <table className="min-w-full rounded-2xl">
        <thead>
          <tr className="border-b bg-gray-100">
            <th className="px-4 py-3 text-left font-semibold"></th>
            <th className="px-4 py-3 text-left font-semibold">Operador</th>
            <th className="px-4 py-3 text-left font-semibold">Auxiliar</th>
            <th className="px-4 py-3 text-left font-semibold">Disciplina</th>
            <th className="px-4 py-3 text-left font-semibold">Paciente</th>
            <th className="px-4 py-3 text-left font-semibold">Telefone</th>
            <th className="px-4 py-3 text-left font-semibold">Data</th>
            <th className="px-4 py-3 text-left font-semibold">Hora</th>
            <th className="px-4 py-3 text-left font-semibold">Status</th>
            <th className="px-4 py-3 text-left font-semibold"></th>
          </tr>
        </thead>
        <tbody>
          {agendamentosFiltrados.map((ag, idx) => (
            <tr key={ag.id || idx} className="border-b last:border-b-0 hover:bg-gray-50">
              <td className="px-4 py-3">{idx + 1}</td>
              <td className="px-4 py-3">{ag.operadorNome}</td>
              <td className="px-4 py-3">{ag.auxiliarNome}</td>
              <td className="px-4 py-3">{ag.disciplinaNome}</td>
              <td className="px-4 py-3">{ag.pacienteNome}</td>
              <td className="px-4 py-3">{ag.telefone}</td>
              <td className="px-4 py-3">{ag.data ? ag.data.slice(0, 10).split('-').reverse().join('/') : ''}</td>
              <td className="px-4 py-3">{ag.hora}</td>
              <td className="px-4 py-3">
                <span
                  className={
                    "inline-block px-4 py-1 rounded-full font-semibold text-sm " +
                    (STATUS_COLORS[ag.status] || "bg-gray-200 text-gray-700")
                  }
                >
                  {STATUS_LABELS[ag.status] || ag.status}
                </span>
              </td>
              <td className="px-4 py-1 flex gap-2">
                {/* Editar */}
                <button
                  onClick={() => onEditar && onEditar(ag)}
                  className="p-2 rounded hover:bg-gray-200 transition relative group"
                  title="Editar"
                  type="button"
                >
                  <svg xmlns="http://www.w3.org/2000/svg"
                    className="h-5 w-5"
                    viewBox="0 0 20 20"
                    fill="gray">
                    <path d="M13.586 3.586a2 2 0 112.828 2.828l-.793.793-2.828-2.828.793-.793zM11.379 5.793L3 14.172V17h2.828l8.38-8.379-2.83-2.828z" />
                  </svg>
                  <span className="absolute left-1/2 -translate-x-1/2 mt-8 w-max bg-gray-900 text-white text-xs rounded py-1 px-2 opacity-0 group-hover:opacity-100 pointer-events-none transition">Editar</span>
                </button>
                {/* Deletar */}
                <button
                  onClick={() => handleDeletar(ag.id)}
                  className="p-2 rounded hover:bg-gray-200 transition relative group"
                  title="Deletar"
                  type="button"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="red">
                    <path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" />
                  </svg>
                  <span className="absolute left-1/2 -translate-x-1/2 mt-8 w-max bg-gray-900 text-white text-xs rounded py-1 px-2 opacity-0 group-hover:opacity-100 pointer-events-none transition">Deletar</span>
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
